using FastEndpoints;
using HappyPumi.Api.Contracts;
using HappyPumi.Api.State;

namespace HappyPumi.Api.Endpoints.Organizations;

/// <summary>CreateService — POST /api/orgs/{org}/services. Creates an IDP service.</summary>
public sealed class CreateServiceEndpoint(IServiceStore services, IAuditLog audit) : EndpointWithoutRequest<Service>
{
    public override void Configure()
    {
        Post("/api/orgs/{orgName}/services");
        AllowAnonymous();
        Description(b => b.WithTags("Organizations").WithSummary("CreateService").WithName("CreateService"));
    }

    public override async Task HandleAsync(CancellationToken ct)
    {
