        var name = body.Str("name");
        if (string.IsNullOrWhiteSpace(name))
        {
            AddError("'name' is required.", "name");
            await Send.ErrorsAsync(400, ct);
            return;
        }

        var row = services.Create(org, name, body.Str("displayName") ?? name, body.Str("description") ?? "");
        if (row is null)
        {
            await Send.ErrorsAsync(409, ct);
            return;
